use std::collections::HashMap;
use std::sync::{Arc, Mutex};

use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Request, Response, Server};
use hyper::rt::Future;

struct WebServer {
    routes: HashMap<String, Box<dyn Fn() -> String + Send + Sync>>,
}

impl WebServer {
    fn new() -> Self {
        WebServer {
            routes: HashMap::new(),
        }
    }

    fn add_route<F>(&mut self, path: &str, handler: F)
    where
        F: Fn() -> String + Send + Sync + 'static,
    {
        self.routes.insert(path.to_string(), Box::new(handler));
    }

    fn handle_request(req: Request<Body>, routes: Arc<Mutex<HashMap<String, Box<dyn Fn() -> String + Send + Sync>>>>) -> impl Future<Item=Response<Body>, Error=hyper::Error> {
        let path = req.uri().path();
        let routes = routes.lock().unwrap();

        if let Some(handler) = routes.get(path) {
            let response = handler();
            futures::future::ok(Response::new(Body::from(response)))
        } else {
            futures::future::ok(Response::builder()
                .status(404)
                .body(Body::from("Not Found"))
                .unwrap())
        }
    }

    fn run(self) {
        let addr = ([127, 0, 0, 1], 3000).into();

        let routes = Arc::new(Mutex::new(self.routes));

        let make_svc = make_service_fn(move |_| {
            let routes = routes.clone();
            service_fn(move |req| Self::handle_request(req, routes.clone()))
        });

        let server = Server::bind(&addr)
            .serve(make_svc)
            .map_err(|e| eprintln!("server error: {}", e));

        hyper::rt::run(server);
    }
}

fn main() {
    let mut server = WebServer::new();

    server.add_route("/home", || {
        "<html><body><h1>Home Page</h1></body></html>".to_string()
    });

    server.add_route("/about", || {
        "<html><body><h1>About Page</h1></body></html>".to_string()
    });

    server.run();
}

