type ResizeRequest struct {
	Image    []byte
	Width    uint
	Height   uint
	Response chan []byte
}

func resizeWorker(requests <-chan ResizeRequest, wg *sync.WaitGroup) {
	defer wg.Done()
	for req := range requests {
		img, _, err := image.Decode(bytes.NewReader(req.Image))
		if err != nil {
			log.Printf("Failed to decode image: %v\n", err)
			req.Response <- nil
			continue
		}

		resizedImg := resize.Resize(req.Width, req.Height, img, resize.Lanczos3)
		var buf bytes.Buffer
		err = jpeg.Encode(&buf, resizedImg, nil)
		if err != nil {
			log.Printf("Failed to encode image: %v\n", err)
			req.Response <- nil
			continue
		}
		req.Response <- buf.Bytes()
	}
}

func main() {
	requests := make(chan ResizeRequest)
	var wg sync.WaitGroup

	// Launch worker goroutines
	numWorkers := 4
	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go resizeWorker(requests, &wg)
	}

	http.HandleFunc("/resize", func(w http.ResponseWriter, r *http.Request) {
		width, err := strconv.Atoi(r.URL.Query().Get("width"))
		if err != nil || width <= 0 {
			http.Error(w, "Invalid width", http.StatusBadRequest)
			return
		}

		height, err := strconv.Atoi(r.URL.Query().Get("height"))
		if err != nil || height <= 0 {
			http.Error(w, "Invalid height", http.StatusBadRequest)
			return
		}

		file, _, err := r.FormFile("image")
		if err != nil {
			http.Error(w, "Failed to read image", http.StatusBadRequest)
			return
		}
		defer file.Close()

		imgData := new(bytes.Buffer)
		imgData.ReadFrom(file)

		responseChan := make(chan []byte)
		req := ResizeRequest{
			Image:    imgData.Bytes(),
			Width:    uint(width),
			Height:   uint(height),
			Response: responseChan,
		}

		requests <- req
		resizedImg := <-responseChan
		if resizedImg == nil {
			http.Error(w, "Failed to process image", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "image/jpeg")
		_, _ = w.Write(resizedImg)
	})

	go func() {
		wg.Wait()
		close(requests)
	}()

	fmt.Println("Image server listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

