use warp::{Filter, Reply};

#[tokio::main]
async fn main() {
    let log_middleware = Arc::new(|logging_level: &'static str| {
        move |method: warp::http::Method, uri: warp::http::Uri| {
            println!("[{}] Method: {}, URI: {}", logging_level, method, uri);
        }
    });

    let modify_headers_middleware = Arc::new(|custom_response_message: &'static str| {
        move |response: warp::reply::Response| {
            warp::reply::with_header(response, "X-Custom-Header", custom_response_message)
        }
    });

    let log_request = warp::any()
        .map({
            let log_middleware = log_middleware.clone();
            || {
                let log = log_middleware("INFO");
                warp::filters::method::MethodFilter::GET.and(warp::path::end()).map(move |method, uri| {
                    log(method, uri);
                })
            }
        })
        .untuple_one();

    let modify_response = warp::any()
        .map({
            let modify_headers_middleware = modify_headers_middleware.clone();
            || {
                let modify = modify_headers_middleware("Processed");
                warp::reply::html("Hello, Warp!").map(move |response| modify(response))
            }
        });

    let routes = log_request.and(modify_response);

    warp::serve(routes).run(([127, 0, 0, 1], 3030)).await;
}

