func encryptFile(filePath string, key []byte, statusChan chan<- string) {
	data, err := ioutil.ReadFile(filePath)
	if err != nil {
		statusChan <- fmt.Sprintf("Error reading file %s: %v", filePath, err)
		return
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		statusChan <- fmt.Sprintf("Error initializing AES for file %s: %v", filePath, err)
		return
	}

	ciphertext := make([]byte, aes.BlockSize+len(data))
	iv := ciphertext[:aes.BlockSize]
	if _, err := io.ReadFull(rand.Reader, iv); err != nil {
		statusChan <- fmt.Sprintf("Error generating IV for file %s: %v", filePath, err)
		return
	}

	stream := cipher.NewCFBEncrypter(block, iv)
	stream.XORKeyStream(ciphertext[aes.BlockSize:], data)

	encryptedFilePath := filePath + ".enc"
	err = ioutil.WriteFile(encryptedFilePath, ciphertext, 0644)
	if err != nil {
		statusChan <- fmt.Sprintf("Error writing encrypted file %s: %v", encryptedFilePath, err)
		return
	}

	statusChan <- fmt.Sprintf("Successfully encrypted %s", filePath)
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <directory> <key>")
		return
	}

	dir := os.Args[1]
	keyHex := os.Args[2]
	key, err := hex.DecodeString(keyHex)
	if err != nil || len(key) != 32 {
		fmt.Println("Error: Key must be a valid 32-byte hex string")
		return
	}

	files, err := ioutil.ReadDir(dir)
	if err != nil {
		fmt.Printf("Error reading directory %s: %v\n", dir, err)
		return
	}

	statusChan := make(chan string)
	var wg sync.WaitGroup

	for _, file := range files {
		if file.Mode().IsRegular() {
			wg.Add(1)
			go func(fileName string) {
				defer wg.Done()
				encryptFile(filepath.Join(dir, fileName), key, statusChan)
			}(file.Name())
		}
	}

	go func() {
		wg.Wait()
		close(statusChan)
	}()

	for status := range statusChan {
		fmt.Println(status)
	}
}

