import java.util.PriorityQueue

data class Task(val priority: Int, val action: () -> Unit) : Comparable<Task> {
    override fun compareTo(other: Task): Int {
        return other.priority - this.priority
    }
}

class TaskScheduler {
    private val taskQueue = PriorityQueue<Task>()

    fun addTask(priority: Int, action: () -> Unit) {
        taskQueue.offer(Task(priority, action))
    }

    fun executeNextTask() {
        taskQueue.poll()?.action?.invoke()
    }

    fun executeAllTasks() {
        while (taskQueue.isNotEmpty()) {
            executeNextTask()
        }
    }
}

fun main() {
    val scheduler = TaskScheduler()

    scheduler.addTask(3) { println("Executing Task with Priority 3") }
    scheduler.addTask(5) { println("Executing Task with Priority 5") }
    scheduler.addTask(1) { println("Executing Task with Priority 1") }

    scheduler.executeAllTasks()
}

