fn convert_temperatures(celsius_list: Vec<i32>) -> Vec<i32> {
    celsius_list
        .into_iter()
        .map(|temp| {
            match temp {
                // Freezing: Below 0°C
                t if t < 0 => (t * 9 / 5) + 32, // Convert Celsius to Fahrenheit

                // Cold: 0°C to 15°C
                t @ 0..=15 => (t * 9 / 5) + 32, // Same conversion formula applies

                // Warm: 16°C to 30°C
                t @ 16..=30 => (t * 9 / 5) + 32, // Convert Celsius to Fahrenheit

                // Hot: Above 30°C
                t if t > 30 => (t * 9 / 5) + 32, // Convert Celsius to Fahrenheit
            }
        })
        .collect()
}

