fun main() {
    embeddedServer(Netty, port = 8080) {
        routing {
            post("/authenticate") {
                val token = call.request.headers["Authorization"]?.substringAfter("Bearer ")
                if (token == null || !isTokenValid(token)) {
                    call.respond(HttpStatusCode.Unauthorized, "Invalid or missing token")
                    return@post
                }

                val userRole = getUserRoleFromToken(token)
                val dynamicRoleCheck: (String) -> Boolean = { requiredRole ->
                    userRole == requiredRole
                }

                val permissionGranted = dynamicRoleCheck("ADMIN") // Example dynamic role check
                if (permissionGranted) {
                    call.respond(HttpStatusCode.OK, "Access granted")
                } else {
                    call.respond(HttpStatusCode.Forbidden, "Access denied")
                }
            }
        }
    }.start(wait = true)
}

fun isTokenValid(token: String): Boolean {
    return try {
        val claims = Jwts.parser()
            .setSigningKey("secret-key") // Replace with your actual signing key
            .parseClaimsJws(token)
            .body

        claims.expiration.after(Date())
    } catch (e: Exception) {
        false
    }
}

fun getUserRoleFromToken(token: String): String {
    val claims = Jwts.parser()
        .setSigningKey("secret-key") // Replace with your actual signing key
        .parseClaimsJws(token)
        .body

    return claims["role"]?.toString() ?: "GUEST"
}

